steps.command:
SELECT column_name, data_type
FROM information_schema.columns
WHERE table_schema = 'bookings' AND table_name = 'ticket_flights';

SELECT indexname, indexdef
FROM pg_indexes
WHERE tablename = 'ticket_flights';

SELECT pg_size_pretty(pg_total_relation_size('bookings.ticket_flights')),
       pg_size_pretty(pg_total_relation_size('bookings.flights')),
       pg_size_pretty(pg_total_relation_size('bookings.tickets'));

SELECT relname, n_live_tup, n_dead_tup
FROM pg_stat_user_tables
WHERE relname IN ('ticket_flights', 'flights', 'tickets');

SELECT indexname, indexdef
FROM pg_indexes
WHERE tablename = 'flights';

EXPLAIN ANALYZE
SELECT * FROM bookings.flights
WHERE flight_no = 'AA123' AND scheduled_departure = '2024-01-01 00:00:00';

SELECT pg_terminate_backend(pid)
FROM pg_stat_activity
WHERE state = 'idle in transaction';

SELECT table_schema, table_name, privilege_type
FROM information_schema.role_table_grants
WHERE grantee = 'app_user';

SELECT
    pg_cancel_backend(221) AS cancelled_221,
    pg_cancel_backend(223) AS cancelled_223;

SELECT indexname, indexdef
FROM pg_indexes
WHERE tablename = 'ticket_flights';

SELECT indexname, indexdef
FROM pg_indexes
WHERE tablename = 'flights';

SELECT
    pg_size_pretty(pg_table_size('bookings.bookings')) AS table_size,
    pg_size_pretty(pg_indexes_size('bookings.bookings')) AS indexes_size;

SELECT
    pg_size_pretty(pg_table_size('bookings.bookings')) AS table_size,
    pg_size_pretty(pg_indexes_size('bookings.bookings')) AS indexes_size;
